package com.example.userapp.network;

import java.util.concurrent.TimeUnit;

import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class RetrofitClient {

    private static volatile RetrofitClient instance;
    private final Retrofit retrofit;
    private final ApiService apiService;

    private RetrofitClient() {
        this(null);
    }

    private RetrofitClient(AuthInterceptor.TokenProvider tokenProvider) {
        OkHttpClient okHttpClient = buildOkHttpClient(tokenProvider);

        retrofit = new Retrofit.Builder()
                .baseUrl(NetworkConfig.BASE_URL)
                .client(okHttpClient)
                .addConverterFactory(GsonConverterFactory.create())
                .build();

        apiService = retrofit.create(ApiService.class);
    }

    public static RetrofitClient getInstance() {
        if (instance == null) {
            synchronized (RetrofitClient.class) {
                if (instance == null) {
                    instance = new RetrofitClient();
                }
            }
        }
        return instance;
    }

    public static RetrofitClient getInstance(AuthInterceptor.TokenProvider tokenProvider) {
        if (instance == null) {
            synchronized (RetrofitClient.class) {
                if (instance == null) {
                    instance = new RetrofitClient(tokenProvider);
                }
            }
        }
        return instance;
    }

    public static void resetInstance() {
        synchronized (RetrofitClient.class) {
            instance = null;
        }
    }

    private OkHttpClient buildOkHttpClient(AuthInterceptor.TokenProvider tokenProvider) {
        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .connectTimeout(NetworkConfig.CONNECT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .readTimeout(NetworkConfig.READ_TIMEOUT_SECONDS, TimeUnit.SECONDS)
                .writeTimeout(NetworkConfig.WRITE_TIMEOUT_SECONDS, TimeUnit.SECONDS);

        // Add auth interceptor if token provider is available
        if (tokenProvider != null) {
            builder.addInterceptor(new AuthInterceptor(tokenProvider));
        }

        // Add logging interceptor for non-production builds
        if (NetworkConfig.ENABLE_LOGGING) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);
            builder.addInterceptor(loggingInterceptor);
        }

        return builder.build();
    }

    public ApiService getApiService() {
        return apiService;
    }

    public Retrofit getRetrofit() {
        return retrofit;
    }
}


